const d = $input.first().json;
const t = new Date().toISOString();
var prompt='Role: Tech Lead. JSON only, no markdown.\nINPUT: '+(d.user_request||d.message||'')+'\nUPSTREAM: '+JSON.stringify(d.upstream_outputs||{})+'\nReturn this exact JSON:\n'+JSON.stringify({request_id:d.request_id||'unknown',persona_name:'AG_03_TECH_LEAD',status:'success|clarification_needed|blocked|failed',summary:'<1 sentence>',structured_output:{implementation_strategy:'<str>',module_breakdown:[{module:'<str>',responsibility:'<str>',complexity:'low|medium|high'}],api_contracts:[{endpoint:'<str>',method:'<str>',request_schema:{},response_schema:{}}],data_models:[{name:'<str>',fields:[{name:'<str>',type:'<str>',required:true}]}],build_order:[{phase:1,modules:[],rationale:'<str>'}],technical_risks:[{risk:'<str>',severity:'low|medium|high',mitigation:'<str>'}]},assumptions:[],risks:[],blocking_questions:[],handoff_recommendation:{next_personas:['AG_05_DELIVERY_PLANNER'],reason:'<str>'},metrics:{started_at:''+t,ended_at:'',duration_ms:0,iteration_count:1}});
var apiBody = {model:'claude-sonnet-4-6',max_tokens:3000,messages:[{role:'user',content:prompt}]};
return [{json:{...d,apiBody,started_at:t}}];

const item = $input.first().json;
const end = new Date().toISOString();
const start = item.started_at || end;
let rawText = '';
try {
  if (item.content && Array.isArray(item.content)) { rawText = item.content[0].text || ''; }
  else if (typeof item.content === 'string') { rawText = item.content; }
} catch(e) {}
let out;
try { var m=rawText.match(/\{[\s\S]*\}/); out=m?JSON.parse(m[0]):{error:'parse_failed',raw:rawText.slice(0,400)}; }
catch(e){ out={error:e.message,raw:rawText.slice(0,400)}; }
var dur=Math.max(0,new Date(end)-new Date(start));
if(out.metrics){out.metrics.ended_at=end;out.metrics.duration_ms=dur;}
return [{json:{
  request_id:item.request_id||'unknown',
  persona_name:out.persona_name||'UNKNOWN',
  status:out.error?'failed':(out.status||'success'),
  summary:out.summary||'Complete.',
  structured_output:out.structured_output||out,
  assumptions:out.assumptions||[],
  risks:out.risks||[],
  blocking_questions:out.blocking_questions||[],
  handoff_recommendation:out.handoff_recommendation||{next_personas:[],reason:'done'},
  metrics:{started_at:start,ended_at:end,duration_ms:dur,iteration_count:1}
}}];
